def z_function(s):
    n = len(s)
    z = [0] * n
    z[0] = n          # the whole string matches its own prefix
    l, r = 0, 0       # current Z-box [l, r)
    for i in range(1, n):
        if i < r:
            z[i] = min(r - i, z[i - l])  # use previously computed info
        # Extend naively beyond the known Z-box
        while i + z[i] < n and s[z[i]] == s[i + z[i]]:
            z[i] += 1
        # Update Z-box if we extended past r
        if i + z[i] > r:
            l, r = ___________
    return z
